import heapq

class Solution:
    def minimumDifference(self, nums):
        total = len(nums)
        n = total // 3
        prefix = [0] * (2 * n + 1)
        heap = []
        s = 0
        for i in range(2 * n):
            val = nums[i]
            heapq.heappush(heap, -val)
            s += val
            if len(heap) > n:
                s += heapq.heappop(heap)
            if i + 1 >= n:
                prefix[i + 1] = s
        suffix = [0] * (2 * n + 1)
        heap2 = []
        s2 = 0
        for i in range(total - 1, n - 1, -1):
            val = nums[i]
            heapq.heappush(heap2, val)
            s2 += val
            if len(heap2) > n:
                s2 -= heapq.heappop(heap2)
            if i <= 2 * n:
                suffix[i] = s2
        best = None
        for i in range(n, 2 * n + 1):
            diff = prefix[i] - suffix[i]
            if best is None or diff < best:
                best = diff
        return best

