function MinHeap() {
    this.a = [];
}
MinHeap.prototype.push = function(v) {
    const a = this.a;
    a.push(v);
    let i = a.length - 1;
    while (i > 0) {
        const p = (i - 1) >> 1;
        if (a[p] <= a[i]) break;
        const tmp = a[p]; a[p] = a[i]; a[i] = tmp;
        i = p;
    }
};
MinHeap.prototype.pop = function() {
    const a = this.a;
    const top = a[0];
    const last = a.pop();
    if (a.length > 0) {
        a[0] = last;
        let i = 0;
        const n = a.length;
        while (true) {
            let l = 2 * i + 1, r = 2 * i + 2, smallest = i;
            if (l < n && a[l] < a[smallest]) smallest = l;
            if (r < n && a[r] < a[smallest]) smallest = r;
            if (smallest === i) break;
            const tmp = a[i]; a[i] = a[smallest]; a[smallest] = tmp;
            i = smallest;
        }
    }
    return top;
};
MinHeap.prototype.size = function() { return this.a.length; };

var minimumDifference = function(nums) {
    const total = nums.length;
    const n = Math.floor(total / 3);
    const prefix = new Array(2 * n + 1).fill(0);
    const maxHeap = new MinHeap();
    let s = 0;
    for (let i = 0; i < 2 * n; i++) {
        const val = nums[i];
        maxHeap.push(-val);
        s += val;
        if (maxHeap.size() > n) {
            s += maxHeap.pop();
        }
        if (i + 1 >= n) prefix[i + 1] = s;
    }
    const suffix = new Array(2 * n + 1).fill(0);
    const minHeap = new MinHeap();
    let s2 = 0;
    for (let i = total - 1; i >= n; i--) {
        const val = nums[i];
        minHeap.push(val);
        s2 += val;
        if (minHeap.size() > n) {
            s2 -= minHeap.pop();
        }
        if (i <= 2 * n) suffix[i] = s2;
    }
    let best = Infinity;
    for (let i = n; i <= 2 * n; i++) {
        best = Math.min(best, prefix[i] - suffix[i]);
    }
    return best;
};
